import dspy
class Router(dspy.Signature):
    '''Plan optimal retrieval queries.'''
    question: str = dspy.InputField()
    plan: str = dspy.OutputField(desc='JSON list of 2-4 subqueries')

class QueryPlanner(dspy.Module):
    def __init__(self):
        super().__init__()
        self.router = dspy.ChainOfThought(Router)

    def forward(self, question):
        return self.router(question=question)

class MultiRetriever(dspy.Module):
    def __init__(self, vectorstore, websearch):
        super().__init__()
        self.vs = vectorstore
        self.web = websearch
        self.grade = dspy.ChainOfThought('query:str -> relevant:bool')

    def forward(self, plan):
        subqueries = json.loads(plan)
        contexts = []
        for q in subqueries:
            vs_results = self.vs.search(q, k=3)
            web_results = self.web.search(q)
            graded = [self.grade(query=q, context=c)['relevant'] 
                     for c in vs_results + web_results]
            contexts.extend([c for c,g in zip(vs_results+web_results,graded) if g])
        return {'contexts': contexts[:8]}

class Synthesizer(dspy.Signature):
    '''Answer using ONLY provided context with [1],[2] citations.'''
    contexts: list[str] = dspy.InputField()
    question: str = dspy.InputField()
    answer: str = dspy.OutputField()
    citations: str = dspy.OutputField(desc='JSON {"[1]": "exact quote", ...}')

class CitedGenerator(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate = dspy.ChainOfThought(Synthesizer)

    def forward(self, contexts, question):
        pred = self.generate(contexts='\n---\n'.join(contexts), question=question)
        return pred

class Critic(dspy.Signature):
    '''Rate 0-10: faithfulness, helpfulness, citation accuracy.'''
    question: str = dspy.InputField()
    answer: str = dspy.InputField()
    contexts: list[str] = dspy.InputField()
    score: str = dspy.OutputField(desc='JSON {"faithfulness":8,"citations":9}')

class SelfCritic(dspy.Module):
    def __init__(self):
        super().__init__()
        self.critic = dspy.ChainOfThought(Critic)

    def forward(self, question, answer, contexts):
        return self.critic(question=question, answer=answer, contexts=contexts)

