    def __init__(self):
        super().__init__()
        self.generate = CitedGenerator()

    @vex.verify(
        assertions=[
            {'type': 'semantic_similarity', 'min_score': 0.85, 
             'a_field': 'answer', 'b_field': 'contexts'},
            {'type': 'citation_verification', 'citations_field': 'citations',
             'contexts_field': 'contexts'}
        ]
    )
    def forward(self, contexts, question):
        return self.generate(contexts=contexts, question=question)

